// Guardar el plan completo en archivo de texto
const fs = require('fs');
const planCompleto = $input.first().json.plan_completo;
const nombreArchivo = $input.first().json.nombre_archivo;
const mes = $input.first().json.mes;
const anio = $input.first().json.anio;

try {
  fs.writeFileSync(nombreArchivo, planCompleto, 'utf8');
  return [{
    json: {
      exito: true,
      archivo: nombreArchivo,
      mensaje: `Plan de ${mes} ${anio} guardado exitosamente en ${nombreArchivo}`,
      tamano_bytes: Buffer.byteLength(planCompleto, 'utf8')
    }
  }];
} catch (error) {
  return [{
    json: {
      exito: false,
      archivo: nombreArchivo,
      error: error.message,
